     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Switch } from "@/components/ui/switch";
     9→import { Textarea } from "@/components/ui/textarea";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    12→import type { Source, SourceInput } from "@/lib/api/types";
    13→import { validateRepository } from "@/lib/format";
    14→import { useTranslation } from "@/lib/i18n/context";
    15→
    16→interface SourceFormProps {
    17→  initial?: Source;
    18→  projectId?: string;
    19→  onSubmit: (input: SourceInput) => Promise<void>;
    20→  title: string;
    21→  redirectTo?: string;
    22→  onSuccess?: () => void;
    23→  onCancel?: () => void;
    24→}
    25→
    26→
    27→const POLL_INTERVAL_KEYS = [
    28→    { labelKey: "sourceForm.intervalHourly", value: "3600" },
    29→    { labelKey: "sourceForm.intervalDaily", value: "86400" },
    30→    { labelKey: "sourceForm.intervalWeekly", value: "604800" },
    31→    { labelKey: "sourceForm.intervalMonthly", value: "2592000" },
    32→  ];
    33→
    34→  function nearestPollInterval(seconds: number): string {
    35→    const values = POLL_INTERVAL_KEYS.map((o) => Number(o.value));
    36→    let closest = values[0];
    37→    for (const v of values) {
    38→      if (Math.abs(v - seconds) < Math.abs(closest - seconds)) closest = v;
    39→    }
    40→    return String(closest);
    41→  }
    42→
    43→
    44→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    45→  const router = useRouter();
    46→  const { t } = useTranslation();
    47→  const [saving, setSaving] = useState(false);
    48→  const [error, setError] = useState("");
    49→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    50→  const [repository, setRepository] = useState(initial?.repository ?? "");
    51→  const [pollInterval, setPollInterval] = useState(
    52→    nearestPollInterval(initial?.poll_interval_seconds ?? 86400)
    53→  );
    54→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    55→  const [configJson, setConfigJson] = useState(
    56→    JSON.stringify(initial?.config ?? {}, null, 2)
    57→  );
    58→  const [versionFilterInclude, setVersionFilterInclude] = useState(initial?.version_filter_include ?? "");
    59→  const [versionFilterExclude, setVersionFilterExclude] = useState(initial?.version_filter_exclude ?? "");
    60→  const [excludePrereleases, setExcludePrereleases] = useState(initial?.exclude_prereleases ?? false);
    61→
    62→  const handleSubmit = async (e: React.FormEvent) => {
    63→    e.preventDefault();
    64→    setError("");
    65→
    66→    const repoError = validateRepository(provider, repository);
    67→    if (repoError) {
    68→      setError(repoError);
    69→      return;
    70→    }
    71→
    72→    let parsedConfig: Record<string, unknown> | undefined;
    73→    if (configJson.trim() && configJson.trim() !== "{}") {
    74→      try {
    75→        parsedConfig = JSON.parse(configJson);
    76→      } catch {
    77→        setError(t("sourceForm.errorInvalidJson"));
    78→        return;
    79→      }
    80→    }
    81→
    82→    setSaving(true);
    83→    try {
    84→      await onSubmit({
    85→        provider,
    86→        repository: repository.trim(),
    87→        poll_interval_seconds: Number(pollInterval),
    88→        enabled,
    89→        config: parsedConfig,
    90→        version_filter_include: versionFilterInclude.trim() || undefined,
    91→        version_filter_exclude: versionFilterExclude.trim() || undefined,
    92→        exclude_prereleases: excludePrereleases || undefined,
    93→      });
    94→      if (onSuccess) {
    95→        onSuccess();
    96→      } else {
    97→        router.push(redirectTo ?? "/sources");
    98→      }
    99→    } catch (err: unknown) {
   100→      setError(err instanceof Error ? err.message : t("sourceForm.errorFailedToSave"));
   101→    } finally {
   102→      setSaving(false);
   103→    }
   104→  };
   105→
   106→  const handleCancel = () => {
   107→    if (onCancel) {
   108→      onCancel();
   109→    } else {
   110→      router.back();
   111→    }
   112→  };
   113→
   114→  const formContent = (
   115→    <form onSubmit={handleSubmit} className="space-y-4">
   116→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
   117→      <div className="space-y-2">
   118→        <Label>{t("sourceForm.provider")}</Label>
   119→        <Select value={provider} onValueChange={setProvider}>
   120→          <SelectTrigger><SelectValue /></SelectTrigger>
   121→          <SelectContent>
   122→            <SelectItem value="dockerhub">{t("sourceForm.providerDockerHub")}</SelectItem>
   123→            <SelectItem value="github">{t("sourceForm.providerGitHub")}</SelectItem>
   124→            <SelectItem value="ecr-public">{t("sourceForm.providerECR")}</SelectItem>
   125→            <SelectItem value="gitlab">{t("sourceForm.providerGitLab")}</SelectItem>
   126→            <SelectItem value="pypi">{t("sourceForm.providerPyPI")}</SelectItem>
   127→            <SelectItem value="npm">{t("sourceForm.providerNpm")}</SelectItem>
   128→          </SelectContent>
   129→        </Select>
   130→      </div>
   131→      <div className="space-y-2">
   132→        <Label htmlFor="repository">{t("sourceForm.repository")}</Label>
   133→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder={t("sourceForm.repositoryPlaceholder")} required />
   134→      </div>
   135→      <div className="space-y-2">
   136→        <Label>{t("sourceForm.pollInterval")}</Label>
   137→        <Select value={pollInterval} onValueChange={setPollInterval}>
   138→          <SelectTrigger><SelectValue /></SelectTrigger>
   139→          <SelectContent>
   140→            {POLL_INTERVAL_KEYS.map((opt) => (
   141→              <SelectItem key={opt.value} value={opt.value}>{t(opt.labelKey)}</SelectItem>
   142→            ))}
   143→          </SelectContent>
   144→        </Select>
   145→      </div>
   146→      <div className="space-y-2">
   147→        <Label htmlFor="config">{t("sourceForm.config")}</Label>
   148→        <Textarea
   149→          id="config"
   150→          value={configJson}
   151→          onChange={(e) => setConfigJson(e.target.value)}
   152→          rows={4}
   153→          className="font-mono text-sm"
   154→          placeholder="{}"
   155→        />
   156→      </div>
   157→      <div className="space-y-2">
   158→        <Label htmlFor="version_filter_include">{t("sourceForm.versionFilterInclude")}</Label>
   159→        <Input
   160→          id="version_filter_include"
   161→          value={versionFilterInclude}
   162→          onChange={(e) => setVersionFilterInclude(e.target.value)}
   163→          placeholder={t("sourceForm.versionFilterIncludePlaceholder")}
   164→          className="font-mono text-sm"
   165→        />
   166→        <p className="text-xs text-muted-foreground">{t("sourceForm.versionFilterIncludeHelper")}</p>
   167→      </div>
   168→      <div className="space-y-2">
   169→        <Label htmlFor="version_filter_exclude">{t("sourceForm.versionFilterExclude")}</Label>
   170→        <Input
   171→          id="version_filter_exclude"
   172→          value={versionFilterExclude}
   173→          onChange={(e) => setVersionFilterExclude(e.target.value)}
   174→          placeholder={t("sourceForm.versionFilterExcludePlaceholder")}
   175→          className="font-mono text-sm"
   176→        />
   177→        <p className="text-xs text-muted-foreground">{t("sourceForm.versionFilterExcludeHelper")}</p>
   178→      </div>
   179→      {(provider === "github" || provider === "gitlab" || provider === "pypi" || provider === "npm") && (
   180→        <div className="flex items-center gap-3">
   181→          <Switch checked={excludePrereleases} onCheckedChange={setExcludePrereleases} />
   182→          <Label>{t("sourceForm.excludePrereleases")}</Label>
   183→        </div>
   184→      )}
   185→      <div className="flex items-center gap-3">
   186→        <Switch checked={enabled} onCheckedChange={setEnabled} />
   187→        <Label>{t("sourceForm.enabled")}</Label>
   188→      </div>
   189→      <div className="flex justify-end gap-2">
   190→        <Button type="button" variant="outline" onClick={handleCancel}>{t("sourceForm.cancel")}</Button>
   191→        <Button type="submit" disabled={saving}>{saving ? t("sourceForm.saving") : t("sourceForm.save")}</Button>
   192→      </div>
   193→    </form>
   194→  );
   195→
   196→  if (onSuccess) {
   197→    return formContent;
   198→  }
   199→
   200→  return (
   201→    <Card className="mx-auto max-w-2xl">
   202→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
   203→      <CardContent>
   204→        {formContent}
   205→      </CardContent>
   206→    </Card>
   207→  );
   208→}
   209→

