     3→import { useState, useEffect, useMemo } from "react";
     4→import useSWR from "swr";
     5→import { gates as gatesApi } from "@/lib/api/client";
     6→import type {
     7→  Source,
     8→  ReleaseGateInput,
     9→  VersionMapping,
    10→  VersionReadiness,
    11→  GateEvent,
    12→} from "@/lib/api/types";
    13→import { Switch } from "@/components/ui/switch";
    14→import { Checkbox } from "@/components/ui/checkbox";
    15→import { Input } from "@/components/ui/input";
    16→import { Textarea } from "@/components/ui/textarea";
    17→import { Button } from "@/components/ui/button";
    18→import { SectionLabel } from "@/components/ui/section-label";
    19→import {
    20→  Select,
    21→  SelectContent,
    22→  SelectItem,
    23→  SelectTrigger,
    24→  SelectValue,
    25→} from "@/components/ui/select";
    26→import { X, Plus } from "lucide-react";
    27→import { timeAgo } from "@/lib/format";
    28→import { useTranslation } from "@/lib/i18n/context";
    29→
    30→interface ReleaseGateTabProps {
    31→  projectId: string;
    32→  sources: Source[];
    33→}
    34→
    35→export function ReleaseGateTab({ projectId, sources }: ReleaseGateTabProps) {
    36→  const { t } = useTranslation();
    37→
    38→  // Source display name lookup
    39→  const sourceNames = useMemo(() => {
    40→    const map: Record<string, string> = {};
    41→    for (const s of sources) {
    42→      map[s.id] = `${s.provider}/${s.repository}`;
    43→    }
    44→    return map;
    45→  }, [sources]);
    46→
    47→  // --- Gate config data ---
    48→  const {
    49→    data: gateData,
    50→    mutate: mutateGate,
    51→    isLoading: gateLoading,
    52→  } = useSWR(`project-${projectId}-gate`, () => gatesApi.get(projectId));
    53→
    54→  const gate = gateData?.data ?? null;
    55→
    56→  // --- Version readiness data (with Load More accumulation) ---
    57→  const [readinessPage, setReadinessPage] = useState(1);
    58→  const [allReadiness, setAllReadiness] = useState<VersionReadiness[]>([]);
    59→  const {
    60→    data: readinessData,
    61→  } = useSWR(
    62→    gate?.enabled ? `project-${projectId}-readiness-${readinessPage}` : null,
    63→    () => gatesApi.listReadiness(projectId, readinessPage)
    64→  );
    65→
    66→  // Accumulate pages
    67→  useEffect(() => {
    68→    if (readinessData?.data) {
    69→      setAllReadiness((prev) =>
    70→        readinessPage === 1 ? readinessData.data! : [...prev, ...readinessData.data!]
    71→      );
    72→    }
    73→  }, [readinessData, readinessPage]);
    74→
    75→  // Reset on gate toggle
    76→  useEffect(() => {
    77→    if (!gate?.enabled) {
    78→      setAllReadiness([]);
    79→      setReadinessPage(1);
    80→    }
    81→  }, [gate?.enabled]);
    82→
    83→  const hasMoreReadiness = (readinessData?.data?.length ?? 0) === 25;
    84→
    85→  // --- Events version filter (set by readiness table "Events" button) ---
    86→  const [eventsVersionFilter, setEventsVersionFilter] = useState<string | null>(null);
    87→
    88→  // --- Gate events data (with Load More accumulation) ---
    89→  const [eventsPage, setEventsPage] = useState(1);
    90→  const [allEvents, setAllEvents] = useState<GateEvent[]>([]);
    91→  const { data: eventsData } = useSWR(
    92→    gate
    93→      ? eventsVersionFilter
    94→        ? `project-${projectId}-gate-events-v-${eventsVersionFilter}-${eventsPage}`
    95→        : `project-${projectId}-gate-events-${eventsPage}`
    96→      : null,
    97→    () =>
    98→      eventsVersionFilter
    99→        ? gatesApi.listEventsByVersion(projectId, eventsVersionFilter, eventsPage)
   100→        : gatesApi.listEvents(projectId, eventsPage)
   101→  );
   102→
   103→  // Accumulate event pages
   104→  useEffect(() => {
   105→    if (eventsData?.data) {
   106→      setAllEvents((prev) =>
   107→        eventsPage === 1 ? eventsData.data! : [...prev, ...eventsData.data!]
   108→      );
   109→    }
   110→  }, [eventsData, eventsPage]);
   111→
   112→  // Reset events when filter changes
   113→  useEffect(() => {
   114→    setAllEvents([]);
   115→    setEventsPage(1);
   116→  }, [eventsVersionFilter]);
   117→
   118→  const hasMoreEvents = (eventsData?.data?.length ?? 0) === 25;
   119→
   120→  // --- Form state ---
   121→  const [enabled, setEnabled] = useState(false);
   122→  const [requiredSources, setRequiredSources] = useState<string[]>([]);
   123→  const [timeoutHours, setTimeoutHours] = useState(168);
   124→  const [nlRule, setNlRule] = useState("");
   125→  const [versionMapping, setVersionMapping] = useState<
   126→    Record<string, VersionMapping>
   127→  >({});
   128→  const [saving, setSaving] = useState(false);
   129→
   130→  // Sync form state from SWR data
   131→  useEffect(() => {
   132→    if (gate) {
   133→      setEnabled(gate.enabled);
   134→      setRequiredSources(gate.required_sources ?? []);
   135→      setTimeoutHours(gate.timeout_hours);
   136→      setNlRule(gate.nl_rule ?? "");
   137→      setVersionMapping(gate.version_mapping ?? {});
   138→    } else {
   139→      setEnabled(false);
   140→      setRequiredSources([]);
   141→      setTimeoutHours(168);
   142→      setNlRule("");
   143→      setVersionMapping({});
   144→    }
   145→  }, [gate]);
   146→
   147→  // --- Handlers ---
   148→  const handleToggleEnabled = async (checked: boolean) => {
   149→    setEnabled(checked);
   150→    if (!gate) return; // no gate yet — will be saved with "Save Configuration"
   151→    try {
   152→      const input: ReleaseGateInput = {
   153→        enabled: checked,
   154→        required_sources: requiredSources.length > 0 ? requiredSources : undefined,
   155→        timeout_hours: timeoutHours,
   156→        version_mapping:
   157→          Object.keys(versionMapping).length > 0 ? versionMapping : undefined,
   158→        nl_rule: nlRule || undefined,
   159→      };
   160→      await gatesApi.upsert(projectId, input);
   161→      mutateGate();
   162→    } catch {
   163→      setEnabled(!checked); // revert on failure
   164→    }
   165→  };
   166→
   167→  const handleSave = async () => {
   168→    setSaving(true);
   169→    try {
   170→      const input: ReleaseGateInput = {
   171→        enabled,
   172→        required_sources: requiredSources.length > 0 ? requiredSources : undefined,
   173→        timeout_hours: timeoutHours,
   174→        version_mapping:
   175→          Object.keys(versionMapping).length > 0 ? versionMapping : undefined,
   176→        nl_rule: nlRule || undefined,
   177→      };
   178→      await gatesApi.upsert(projectId, input);
   179→      mutateGate();
   180→    } finally {
   181→      setSaving(false);
   182→    }
   183→  };
   184→
   185→  const toggleSource = (sourceId: string) => {
   186→    setRequiredSources((prev) =>
   187→      prev.includes(sourceId)
   188→        ? prev.filter((id) => id !== sourceId)
   189→        : [...prev, sourceId]
   190→    );
   191→  };
   192→
   193→  // Version mapping helpers
   194→  const [addMappingSourceId, setAddMappingSourceId] = useState("");
   195→  const mappedSourceIds = Object.keys(versionMapping);
   196→  const unmappedSources = sources.filter((s) => !mappedSourceIds.includes(s.id));
   197→
   198→  const addMapping = () => {
   199→    if (!addMappingSourceId) return;
   200→    setVersionMapping((prev) => ({
   201→      ...prev,
   202→      [addMappingSourceId]: { pattern: "", template: "" },
   203→    }));
   204→    setAddMappingSourceId("");
   205→  };
   206→
   207→  const removeMapping = (sourceId: string) => {
   208→    setVersionMapping((prev) => {
   209→      const next = { ...prev };
   210→      delete next[sourceId];
   211→      return next;
   212→    });
   213→  };
   214→
   215→  const updateMapping = (
   216→    sourceId: string,
   217→    field: "pattern" | "template",
   218→    value: string
   219→  ) => {
   220→    setVersionMapping((prev) => ({
   221→      ...prev,
   222→      [sourceId]: { ...prev[sourceId], [field]: value },
   223→    }));
   224→  };
   225→
   226→  // Relative time formatter for timeout countdown
   227→  const formatTimeRemaining = (timeoutAt: string, status: string): string => {
   228→    if (status === "ready") return "—";
   229→    if (status === "timed_out") return t("projects.detail.vrExpired");
   230→    const diff = new Date(timeoutAt).getTime() - Date.now();
   231→    if (diff <= 0) return t("projects.detail.vrExpired");
   232→    const hours = Math.floor(diff / 3600000);
   233→    const mins = Math.floor((diff % 3600000) / 60000);
   234→    if (hours > 24) return `${Math.floor(hours / 24)}d ${hours % 24}h`;
   235→    if (hours > 0) return `${hours}h ${mins}m`;
   236→    return `${mins}m`;
   237→  };
   238→
   239→  const statusBadge = (status: string) => {
   240→    switch (status) {
   241→      case "ready":
   242→        return (
   243→          <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs bg-green-500/10 text-green-500">
   244→            {t("projects.detail.vrReady")}
   245→          </span>
   246→        );
