#### **A. Source Form Component** 
**File:** `/Users/pc/web3/ReleaseBeacon/web/components/sources/source-form.tsx`

Uses Switch components inline with labels:

```typescript
// Lines 180-183
{(provider === "github" || provider === "gitlab" || provider === "pypi" || provider === "npm") && (
  <div className="flex items-center gap-3">
    <Switch checked={excludePrereleases} onCheckedChange={setExcludePrereleases} />
    <Label>{t("sourceForm.excludePrereleases")}</Label>
  </div>
)}

// Lines 185-188
<div className="flex items-center gap-3">
  <Switch checked={enabled} onCheckedChange={setEnabled} />
  <Label>{t("sourceForm.enabled")}</Label>
</div>
```

**Styling:** Simple flex horizontal layout with gap-3 spacing

#### **B. Release Gate Tab Component**
**File:** `/Users/pc/web3/ReleaseBeacon/web/components/projects/release-gate-tab.tsx`

Uses both Checkbox and Switch components with different patterns:

**Checkbox usage for required sources selection (lines 338-349):**
```typescript
<label
  key={s.id}
  className="flex items-center gap-2 px-3 py-1.5 rounded-md border text-sm cursor-pointer hover:bg-accent/50"
>
  <Checkbox
    checked={requiredSources.includes(s.id)}
    onCheckedChange={() => toggleSource(s.id)}
  />
  {sourceNames[s.id]}
</label>
```

**Switch for gate enabled toggle (lines 471-480):**
```typescript
<div className="flex items-center gap-2">
  <Switch
    id="gate-enabled"
    checked={enabled}
    onCheckedChange={handleToggleEnabled}
  />
  <label htmlFor="gate-enabled" className="text-[13px] text-secondary-foreground">
    {t("projects.detail.gateEnabled")}
  </label>
</div>
```

#### **C. Subscription Form Component**
**File:** `/Users/pc/web3/ReleaseBeacon/web/components/subscriptions/subscription-form.tsx`

Uses Checkbox for multi-select with toggle functions:

```typescript
// Lines 81-85
const toggleProjectId = (id: string) => {
  setSelectedProjectIds((prev) =>
    prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
  );
};

// Lines 188-194 (Checkbox layout)
<label key={p.id} className="flex items-center gap-2 rounded px-2 py-1.5 hover:bg-accent cursor-pointer">
  <Checkbox
    checked={selectedProjectIds.includes(p.id)}
    onCheckedChange={() => toggleProjectId(p.id)}
  />
  <span className="text-sm">{p.name}</span>
</label>
```

**Select All/Toggle button (lines 178-184):**
```typescript
<button
  type="button"
  onClick={toggleAllProjects}
  className="text-xs text-blue-600 hover:text-blue-800"
>
  {selectedProjectIds.length === allProjectIds.length ? t("subscriptionForm.deselectAll") : t("subscriptionForm.selectAll")}
</button>
```

#### **D. Native HTML Checkboxes**

**File:** `/Users/pc/web3/ReleaseBeacon/web/components/projects/project-detail.tsx`

Raw HTML checkboxes with custom styling for trigger rules:

```typescript
<label className="flex items-center gap-2.5 text-[13px] text-secondary-foreground">
  <input
    type="checkbox"
    checked={currentRules.on_major_release ?? false}
    onChange={(e) =>
      setRulesDraft({ ...currentRules, on_major_release: e.target.checked })
