    style={{ borderColor: "var(--border)" }}
  />
  {t("projects.detail.majorRelease")}
</label>
```

**Styling:** 4×4 size, rounded corners, custom accent orange color (#e8601a), inline with text

**File:** `/Users/pc/web3/ReleaseBeacon/web/components/projects/project-form.tsx`

```typescript
<input
  type="checkbox"
  checked={excludePrereleases}
  onChange={(e) => setExcludePrereleases(e.target.checked)}
  className="rounded"
/>
```

**File:** `/Users/pc/web3/ReleaseBeacon/web/components/dashboard/shared/scan-results-table.tsx`

Table header and row checkboxes for bulk selection:

```typescript
// Line 35-46 (Header checkbox)
<input
  type="checkbox"
  checked={selectedCount === deps.length}
  onChange={(e) => {
    const val = e.target.checked;
    const s: Record<number, boolean> = {};
    deps.forEach((_, i) => { s[i] = val; });
    onSelectionsChange(s);
  }}
  className="rounded"
  style={{ accentColor: "var(--beacon-accent)" }}
/>

// Line 78-84 (Row checkbox)
<input
  type="checkbox"
  checked={!!selections[i]}
  onChange={(e) => onSelectionsChange({ ...selections, [i]: e.target.checked })}
  className="rounded"
  style={{ accentColor: "var(--beacon-accent)" }}
