     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { useState, useRef, useEffect, useCallback } from "react";
     6→import { useRouter, useSearchParams } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→  contextSources as ctxApi,
    11→  agent as agentApi,
    12→  releases as releasesApi,
    13→} from "@/lib/api/client";
    14→import type { AgentRules, Source } from "@/lib/api/types";
    15→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    16→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    17→import { SourceForm } from "@/components/sources/source-form";
    18→import { NewContextSourceForm } from "@/components/context-sources/new-context-source-form";
    19→import { ReleaseGateTab } from "./release-gate-tab";
    20→import { ProjectLogo } from "@/components/ui/project-logo";
    21→import { ProviderBadge } from "@/components/ui/provider-badge";
    22→import { StatusDot } from "@/components/ui/status-dot";
    23→import { SectionLabel } from "@/components/ui/section-label";
    24→import { formatInterval } from "@/lib/format";
    25→import { getPathSegment } from "@/lib/path";
    26→import { Pencil, Trash2, Play, Plus, ArrowLeft } from "lucide-react";
    27→import { useTranslation } from "@/lib/i18n/context";
    28→
    29→/* ---------- Tabs ---------- */
    30→
    31→type TabKey = "sources" | "context" | "agent" | "gates";
    32→
    33→/* ---------- Helpers ---------- */
    34→
    35→function formatDuration(startedAt?: string, completedAt?: string): string {
    36→  if (!startedAt) return "--";
    37→  const start = new Date(startedAt).getTime();
    38→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    39→  const secs = Math.round((end - start) / 1000);
    40→  if (secs < 60) return `${secs}s`;
    41→  const mins = Math.floor(secs / 60);
    42→  const rem = secs % 60;
    43→  return `${mins}m ${rem}s`;
    44→}
    45→
    46→function truncate(str: string, max: number): string {
    47→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    48→}
    49→
    50→/* ---------- Main component ---------- */
    51→
    52→export function ProjectDetail() {
    53→  const { t } = useTranslation();
    54→  // Read ID from URL path — useParams() returns stale "0" in static export
    55→  const id = getPathSegment(1); // /projects/{id}
    56→  const router = useRouter();
    57→  const searchParams = useSearchParams();
    58→
    59→  const validTabs: TabKey[] = ["sources", "context", "agent", "gates"];
    60→  const tabParam = searchParams.get("tab") as TabKey | null;
    61→  const [activeTab, setActiveTabState] = useState<TabKey>(
    62→    tabParam && validTabs.includes(tabParam) ? tabParam : "sources"
    63→  );
    64→
    65→  const setActiveTab = (tab: TabKey) => {
    66→    setActiveTabState(tab);
    67→    const url = new URL(window.location.href);
    68→    if (tab === "sources") {
    69→      url.searchParams.delete("tab");
    70→    } else {
    71→      url.searchParams.set("tab", tab);
    72→    }
    73→    window.history.replaceState({}, "", url.toString());
    74→  };
    75→
    76→  const tabs = [
    77→    { key: "sources" as TabKey, label: t("projects.detail.tabSources") },
    78→    { key: "context" as TabKey, label: t("projects.detail.tabContext") },
    79→    { key: "agent" as TabKey, label: t("projects.detail.tabAgent") },
    80→    { key: "gates" as TabKey, label: t("projects.detail.tabGates") },
    81→  ];
    82→
    83→  /* Test run state */
    84→  const [testSourceId, setTestSourceId] = useState<string>("");
    85→  const [testVersion, setTestVersion] = useState<string>("");
    86→  const [testRunning, setTestRunning] = useState(false);
    87→
    88→  /* Agent config local state */
    89→  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    90→  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    91→  const [saving, setSaving] = useState(false);
    92→
    93→  /* Inline edit state */
    94→  const [editingName, setEditingName] = useState(false);
    95→  const [editingDesc, setEditingDesc] = useState(false);
    96→  const [nameDraft, setNameDraft] = useState("");
    97→  const [descDraft, setDescDraft] = useState("");
    98→  const nameRef = useRef<HTMLInputElement>(null);
    99→  const descRef = useRef<HTMLInputElement>(null);
   100→
   101→  /* Dialog state */
   102→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
   103→  const [editingSource, setEditingSource] = useState<Source | null>(null);
   104→  const [deletingSourceId, setDeletingSourceId] = useState<string | null>(null);
   105→  const [ctxCreateOpen, setCtxCreateOpen] = useState(false);
   106→  const [deletingCtxId, setDeletingCtxId] = useState<string | null>(null);
   107→  const [deletingProject, setDeletingProject] = useState(false);
   108→
   109→  /* Data fetching */
   110→  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
   111→  const { data: sourcesData, mutate: mutateSources } = useSWR(
   112→    `project-${id}-sources`,
   113→    () => sourcesApi.listByProject(id),
   114→  );
   115→  const { data: ctxData, mutate: mutateCtx } = useSWR(
   116→    `project-${id}-ctx`,
   117→    () => ctxApi.list(id),
   118→  );
   119→  const { data: runsData, mutate: mutateRuns } = useSWR(
   120→    activeTab === "agent" ? `project-${id}-runs` : null,
   121→    () => agentApi.listRuns(id),
   122→  );
   123→  const { data: testReleasesData } = useSWR(
   124→    testSourceId ? `source-${testSourceId}-releases` : null,
   125→    () => releasesApi.listBySource(testSourceId, 1),
   126→  );
   127→
   128→  const saveName = useCallback(async () => {
   129→    const p = data?.data;
   130→    if (!p) return;
   131→    const trimmed = nameDraft.trim();
   132→    if (trimmed && trimmed !== p.name) {
   133→      await projectsApi.update(id, { name: trimmed, description: p.description });
   134→      mutateProject();
   135→    }
   136→    setEditingName(false);
   137→  }, [nameDraft, data, id, mutateProject]);
   138→
   139→  const saveDesc = useCallback(async () => {
   140→    const p = data?.data;
   141→    if (!p) return;
   142→    const trimmed = descDraft.trim();
   143→    if (trimmed !== (p.description ?? "")) {
   144→      await projectsApi.update(id, { name: p.name, description: trimmed || undefined });
   145→      mutateProject();
   146→    }
   147→    setEditingDesc(false);
   148→  }, [descDraft, data, id, mutateProject]);
   149→
   150→  /* Click-outside handlers */
   151→  useEffect(() => {
