   660→                  disabled={saving || (promptDraft === null && rulesDraft === null)}
   661→                  className="rounded-md px-4 py-1.5 text-[13px] font-medium text-white transition-colors disabled:opacity-40 bg-beacon-accent"
   662→                >
   663→                  {saving ? t("projects.detail.saving") : t("projects.detail.saveSettings")}
   664→                </button>
   665→              </div>
   666→            </div>
   667→
   668→            {/* Card 3: Test Run */}
   669→            <div
   670→              className="rounded-lg border p-5 bg-surface"
   671→              style={{ borderColor: "var(--border)" }}
   672→            >
   673→              <SectionLabel className="mb-1">{t("projects.detail.testRun")}</SectionLabel>
   674→              <p className="mb-4 text-[12px] text-text-muted">
   675→                {t("projects.detail.testRunDesc")}
