   683→                    value={testSourceId}
   684→                    onChange={(e) => {
   685→                      setTestSourceId(e.target.value);
   686→                      setTestVersion("");
   687→                    }}
   688→                    className="w-full rounded-md border px-3 py-1.5 text-[13px] focus:outline-none focus:ring-1 bg-background border-border"
   689→                    style={{
   690→                      fontFamily: "var(--font-dm-sans), sans-serif",
   691→                      color: testSourceId ? "var(--foreground)" : "var(--text-muted)",
   692→                    }}
   693→                  >
   694→                    <option value="">{t("projects.detail.selectSource")}</option>
   695→                    {sourcesData?.data?.map((s) => (
   696→                      <option key={s.id} value={s.id}>
   697→                        {s.provider}: {s.repository}
   698→                      </option>
   699→                    ))}
   700→                  </select>
   701→                </div>
   702→                <div className="min-w-[200px] flex-1">
   703→                  <label className="mb-1.5 block text-[13px] text-secondary-foreground">
   704→                    {t("projects.detail.version")}
   705→                  </label>
   706→                  <select
   707→                    value={testVersion}
