   709→                    disabled={!testSourceId}
   710→                    className="w-full rounded-md border px-3 py-1.5 text-[13px] focus:outline-none focus:ring-1 disabled:opacity-50 bg-background border-border"
   711→                    style={{
   712→                      fontFamily: "'JetBrains Mono', monospace",
