   745→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-text-muted">{t("projects.detail.trigger")}</th>
   746→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-text-muted">{t("projects.detail.status")}</th>
   747→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-text-muted">{t("projects.detail.started")}</th>
   748→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-text-muted">{t("projects.detail.duration")}</th>
   749→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-text-muted">{t("projects.detail.semanticRelease")}</th>
   750→                      </tr>
   751→                    </thead>
   752→                    <tbody>
   753→                      {runsData.data.map((run) => (
   754→                        <tr key={run.id} className="border-t" style={{ borderColor: "var(--border)" }}>
