   771→                          </td>
   772→                          <td className="px-4 py-3">
   773→                            {run.semantic_release_id ? (
   774→                              <Link
   775→                                href={`/projects/${id}/semantic-releases/${run.semantic_release_id}`}
   776→                                className="text-[13px] font-medium underline text-beacon-accent"
   777→                              >
   778→                                {t("projects.detail.view")}
   779→                              </Link>
   780→                            ) : (
   781→                              <span className="text-text-muted">--</span>
