   804→          />
   805→        )}
   806→      </div>
   807→
   808→      {/* Source create dialog */}
   809→      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
   810→        <DialogContent className="sm:max-w-lg">
   811→          <DialogHeader><DialogTitle>{t("projects.detail.dialogAddSource")}</DialogTitle></DialogHeader>
   812→          <SourceForm
   813→            title={t("projects.detail.dialogAddSource")}
   814→            projectId={id}
   815→            onSubmit={async (input) => { const res = await sourcesApi.create(id, input); if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {}); }}
   816→            onSuccess={() => { setSourceCreateOpen(false); mutateSources(); }}
   817→            onCancel={() => setSourceCreateOpen(false)}
   818→          />
