   822→      {/* Source edit dialog */}
   823→      <Dialog open={!!editingSource} onOpenChange={(open) => { if (!open) setEditingSource(null); }}>
   824→        <DialogContent className="sm:max-w-lg">
   825→          <DialogHeader><DialogTitle>{t("projects.detail.dialogEditSource")}</DialogTitle></DialogHeader>
   826→          {editingSource && (
   827→            <SourceForm
   828→              key={editingSource.id}
   829→              title={t("projects.detail.dialogEditSource")}
   830→              initial={editingSource}
   831→              onSubmit={async (input) => { await sourcesApi.update(editingSource.id, input); }}
   832→              onSuccess={() => { setEditingSource(null); mutateSources(); }}
   833→              onCancel={() => setEditingSource(null)}
   834→            />
   835→          )}
   836→        </DialogContent>
   837→      </Dialog>
   838→
   839→      {/* Source delete dialog */}
   840→      <ConfirmDialog
   841→        open={!!deletingSourceId}
