   846→      />
   847→
   848→      {/* Context source create dialog */}
   849→      <Dialog open={ctxCreateOpen} onOpenChange={setCtxCreateOpen}>
   850→        <DialogContent className="sm:max-w-lg">
   851→          <DialogHeader><DialogTitle>{t("projects.detail.dialogAddContextSource")}</DialogTitle></DialogHeader>
   852→          <NewContextSourceForm
   853→            projectId={id}
   854→            onSuccess={() => { setCtxCreateOpen(false); mutateCtx(); }}
   855→            onCancel={() => setCtxCreateOpen(false)}
   856→          />
