     1→package api
     2→
     3→import (
     4→	"context"
     5→	"net/http"
     6→
     7→	"github.com/sentioxyz/changelogue/internal/models"
     8→)
     9→
    10→// TodosStore defines the data access interface for TODO operations.
    11→type TodosStore interface {
    12→	ListTodos(ctx context.Context, status string, page, perPage int, aggregated bool, filter TodoFilter) ([]models.Todo, int, error)
    13→	GetTodo(ctx context.Context, id string) (*models.Todo, error)
    14→	AcknowledgeTodo(ctx context.Context, id string, cascade bool) error
    15→	ResolveTodo(ctx context.Context, id string, cascade bool) error
    16→	ReopenTodo(ctx context.Context, id string) error
    17→}
    18→
    19→// TodosHandler handles HTTP requests for release TODOs.
    20→type TodosHandler struct {
    21→	store     TodosStore
    22→	publicURL string
    23→}
    24→
    25→// NewTodosHandler creates a new TodosHandler.
    26→func NewTodosHandler(store TodosStore, publicURL string) *TodosHandler {
    27→	return &TodosHandler{store: store, publicURL: publicURL}
    28→}
    29→
    30→// List returns a paginated list of TODOs, optionally filtered by status.
    31→func (h *TodosHandler) List(w http.ResponseWriter, r *http.Request) {
    32→	page, perPage := ParsePagination(r)
    33→	status := r.URL.Query().Get("status")
    34→	aggregated := r.URL.Query().Get("aggregated") == "true"
    35→	filter := ParseTodoFilters(r)
    36→
    37→	todos, total, err := h.store.ListTodos(r.Context(), status, page, perPage, aggregated, filter)
    38→	if err != nil {
    39→		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
    40→		return
    41→	}
    42→	if todos == nil {
    43→		todos = []models.Todo{}
    44→	}
    45→	RespondList(w, r, http.StatusOK, todos, page, perPage, total)
    46→}
    47→
    48→// Get returns a single TODO by ID.
    49→func (h *TodosHandler) Get(w http.ResponseWriter, r *http.Request) {
    50→	id := r.PathValue("id")
    51→	todo, err := h.store.GetTodo(r.Context(), id)
    52→	if err != nil {
    53→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    54→		return
    55→	}
    56→	RespondJSON(w, r, http.StatusOK, todo)
    57→}
    58→
    59→// Acknowledge marks a TODO as acknowledged. Supports both PATCH (API) and GET with redirect (notification links).
    60→func (h *TodosHandler) Acknowledge(w http.ResponseWriter, r *http.Request) {
    61→	id := r.PathValue("id")
    62→	cascade := r.URL.Query().Get("cascade") == "true"
    63→	if err := h.store.AcknowledgeTodo(r.Context(), id, cascade); err != nil {
    64→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    65→		return
    66→	}
    67→
    68→	// If redirect=true, send 302 to the frontend todo page.
    69→	if r.URL.Query().Get("redirect") == "true" && h.publicURL != "" {
    70→		http.Redirect(w, r, h.publicURL+"/todo", http.StatusFound)
    71→		return
    72→	}
    73→
    74→	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "acknowledged"})
    75→}
    76→
    77→// Resolve marks a TODO as resolved. Supports both PATCH (API) and GET with redirect (notification links).
    78→func (h *TodosHandler) Resolve(w http.ResponseWriter, r *http.Request) {
    79→	id := r.PathValue("id")
    80→	cascade := r.URL.Query().Get("cascade") == "true"
    81→	if err := h.store.ResolveTodo(r.Context(), id, cascade); err != nil {
    82→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    83→		return
    84→	}
    85→
    86→	// If redirect=true, send 302 to the frontend todo page.
    87→	if r.URL.Query().Get("redirect") == "true" && h.publicURL != "" {
    88→		http.Redirect(w, r, h.publicURL+"/todo", http.StatusFound)
    89→		return
    90→	}
    91→
    92→	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "resolved"})
    93→}
    94→
    95→// Reopen marks a TODO as pending again, clearing acknowledged/resolved timestamps.
    96→func (h *TodosHandler) Reopen(w http.ResponseWriter, r *http.Request) {
    97→	id := r.PathValue("id")
    98→	if err := h.store.ReopenTodo(r.Context(), id); err != nil {
    99→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
   100→		return
   101→	}
   102→
   103→	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "pending"})
   104→}
