		).Scan(&sub.ID, &sub.CreatedAt)
		if err != nil {
			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
		}
		result = append(result, sub)
	}

	if err := tx.Commit(ctx); err != nil {
		return nil, fmt.Errorf("commit tx: %w", err)
	}
	return result, nil
}

