     1→/**
     2→ * Urgency Pill — shared badge component for semantic release urgency.
     3→ *
     4→ * ## Urgency Levels
     5→ *
     6→ * | Level    | Icon            | Color   | Meaning                                    |
     7→ * |----------|-----------------|---------|--------------------------------------------|
     8→ * | critical | AlertOctagon    | Red     | Breaking changes, security patches          |
     9→ * | high     | AlertTriangle   | Orange  | Significant API changes, deprecations       |
    10→ * | medium   | Circle          | Amber   | Notable changes worth reviewing             |
    11→ * | low      | CheckCircle     | Green   | Routine updates, dependency bumps           |
    12→ *
    13→ * ## Variants
    14→ *
    15→ * - **icon-only** (default): 18×18 circle with just the icon. Best for compact
    16→ *   spaces like the projects page where multiple versions are listed inline.
    17→ *   Urgency label is shown on hover via `title`.
    18→ *
    19→ * - **labeled**: Icon + text label in a rounded pill. Best for table rows
    20→ *   (releases page) where there's dedicated column space.
    21→ */
    22→import { AlertOctagon, AlertTriangle, Circle, CheckCircle } from "lucide-react";
    23→import type { LucideIcon } from "lucide-react";
    24→
    25→interface UrgencyStyle {
    26→  icon: LucideIcon;
    27→  bg: string;
    28→  border: string;
    29→  text: string;
    30→}
    31→
    32→export const URGENCY_STYLES: Record<string, UrgencyStyle> = {
    33→  critical: { icon: AlertOctagon, bg: "rgba(220,38,38,0.10)", border: "rgba(220,38,38,0.20)", text: "#dc2626" },
    34→  high:     { icon: AlertTriangle, bg: "rgba(249,115,22,0.10)", border: "rgba(249,115,22,0.20)", text: "#ea580c" },
    35→  medium:   { icon: Circle,        bg: "rgba(245,158,11,0.10)", border: "rgba(245,158,11,0.20)", text: "#d97706" },
    36→  low:      { icon: CheckCircle,   bg: "rgba(34,197,94,0.08)",  border: "rgba(34,197,94,0.18)",  text: "#16a34a" },
    37→};
    38→
    39→/** Solid-background urgency colors (used for compact badges in the sidebar/feed). */
    40→export const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    41→  critical: { bg: "#dc2626", text: "#ffffff" },
    42→  high:     { bg: "#f97316", text: "#ffffff" },
    43→  medium:   { bg: "#f59e0b", text: "#ffffff" },
    44→  low:      { bg: "#6b7280", text: "#ffffff" },
    45→};
    46→
    47→interface UrgencyPillProps {
    48→  urgency: string;
    49→  /** "icon-only" = compact circle, "labeled" = icon + text pill */
    50→  variant?: "icon-only" | "labeled";
    51→  className?: string;
    52→}
    53→
    54→export function UrgencyPill({ urgency, variant = "icon-only", className }: UrgencyPillProps) {
    55→  const style = URGENCY_STYLES[urgency.toLowerCase()];
    56→  if (!style) return null;
    57→
    58→  const Icon = style.icon;
    59→
    60→  if (variant === "icon-only") {
    61→    return (
    62→      <span
    63→        className={`inline-flex items-center justify-center rounded-full ${className ?? ""}`}
    64→        style={{ backgroundColor: style.bg, border: `1px solid ${style.border}`, color: style.text, width: 18, height: 18 }}
    65→        title={urgency}
    66→      >
    67→        <Icon size={10} />
    68→      </span>
    69→    );
    70→  }
    71→
    72→  return (
    73→    <span
    74→      className={`inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 text-[10px] font-semibold ${className ?? ""}`}
    75→      style={{ backgroundColor: style.bg, border: `1px solid ${style.border}`, color: style.text, fontFamily: "var(--font-dm-sans)" }}
    76→      title={urgency}
    77→    >
    78→      <Icon size={10} /> {urgency}
    79→    </span>
    80→  );
    81→}
    82→

