   125→        : releasesApi.list(page, PER_PAGE, apiFilters),
   126→    { refreshInterval: 30_000 }
   127→  );
   128→
   129→  /* Releases come pre-enriched with project/source metadata from the backend */
   130→  const releases: Release[] = data?.data ?? [];
