   135→  const startRow = (page - 1) * PER_PAGE + 1;
   136→  const endRow = Math.min(page * PER_PAGE, total);
   137→
   138→  /* SSE revalidation — refresh on semantic_release events */
   139→  const revalidateReleases = useCallback(() => {
   140→    return mutate((key) => {
   141→      if (Array.isArray(key)) {
   142→        return key[0] === "releases" || key[0] === "all-releases";
   143→      }
   144→      return false;
   145→    }, undefined, { revalidate: true });
   146→  }, []);
   147→
   148→  useEffect(() => {
