    34→      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    35→    case "MEDIUM":
    36→      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    37→    case "LOW":
    38→    default:
    39→      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    40→  }
    41→}
    42→
    43→function safeHostname(url: string): string {
    44→  try {
    45→    return new URL(url).hostname.replace("www.", "");
    46→  } catch {
    47→    return url;
    48→  }
    49→}
    50→
    51→function getDownloadLabel(url: string): { label: string; isDirect: boolean } {
    52→  const lower = url.toLowerCase();
    53→  const filename = lower.split("/").pop() ?? "";
    54→
    55→  // Detect platform from common patterns in the URL or filename
    56→  const platforms: [RegExp, string][] = [
    57→    [/linux.*amd64|amd64.*linux/, "Linux x64"],
    58→    [/linux.*arm64|arm64.*linux|linux.*aarch64/, "Linux ARM64"],
    59→    [/linux.*386|linux.*i386/, "Linux x86"],
    60→    [/darwin.*arm64|arm64.*darwin|macos.*arm64|osx.*arm64/, "macOS ARM64"],
    61→    [/darwin.*amd64|amd64.*darwin|macos.*amd64|osx.*amd64/, "macOS x64"],
    62→    [/darwin|macos|osx/, "macOS"],
    63→    [/windows.*amd64|amd64.*windows|win64/, "Windows x64"],
    64→    [/windows.*386|win32/, "Windows x86"],
    65→    [/windows/, "Windows"],
    66→  ];
    67→
    68→  // Check if this is a direct binary (archive or executable)
    69→  const isArchive = /\.(tar\.gz|tar\.xz|zip|deb|rpm|dmg|msi|exe|pkg|appimage)(\?|$)/i.test(url);
    70→
    71→  if (isArchive) {
    72→    for (const [pattern, label] of platforms) {
    73→      if (pattern.test(filename) || pattern.test(url)) {
    74→        return { label, isDirect: true };
    75→      }
    76→    }
    77→    // Direct download but platform unknown — use filename
    78→    const cleanName = (url.split("/").pop() ?? "").split("?")[0];
    79→    return { label: cleanName || safeHostname(url), isDirect: true };
    80→  }
    81→
    82→  // Not a direct binary — generic link
    83→  return { label: safeHostname(url), isDirect: false };
    84→}
