     1→"use client";
     2→
     3→import { useState, useCallback, useEffect } from "react";
     4→import { CheckCircle2, XCircle, X } from "lucide-react";
     5→
     6→type ToastVariant = "success" | "error";
     7→
     8→interface Toast {
     9→  id: number;
    10→  message: string;
    11→  variant: ToastVariant;
    12→}
    13→
    14→let toastId = 0;
    15→
    16→export function useToast() {
    17→  const [toasts, setToasts] = useState<Toast[]>([]);
    18→
    19→  const show = useCallback((message: string, variant: ToastVariant = "success") => {
    20→    const id = ++toastId;
    21→    setToasts((prev) => [...prev, { id, message, variant }]);
    22→    return id;
    23→  }, []);
    24→
    25→  const dismiss = useCallback((id: number) => {
    26→    setToasts((prev) => prev.filter((t) => t.id !== id));
    27→  }, []);
    28→
    29→  return { toasts, show, dismiss };
    30→}
    31→
    32→export function ToastContainer({
    33→  toasts,
    34→  onDismiss,
    35→}: {
    36→  toasts: Toast[];
    37→  onDismiss: (id: number) => void;
    38→}) {
    39→  return (
    40→    <div className="pointer-events-none fixed bottom-6 right-6 z-50 flex flex-col gap-2">
    41→      {toasts.map((toast) => (
    42→        <ToastItem key={toast.id} toast={toast} onDismiss={onDismiss} />
    43→      ))}
    44→    </div>
    45→  );
    46→}
    47→
    48→function ToastItem({
    49→  toast,
    50→  onDismiss,
    51→}: {
    52→  toast: Toast;
    53→  onDismiss: (id: number) => void;
    54→}) {
    55→  useEffect(() => {
    56→    const timer = setTimeout(() => onDismiss(toast.id), 4000);
    57→    return () => clearTimeout(timer);
    58→  }, [toast.id, onDismiss]);
    59→
    60→  const isSuccess = toast.variant === "success";
    61→
    62→  return (
    63→    <div
    64→      className="pointer-events-auto flex items-center gap-2.5 rounded-lg border px-4 py-3 shadow-lg animate-in slide-in-from-right-5 fade-in"
    65→      style={{
    66→        backgroundColor: isSuccess ? "#f0fdf4" : "#fef2f2",
    67→        borderColor: isSuccess ? "#bbf7d0" : "#fecaca",
    68→        fontFamily: "var(--font-dm-sans)",
    69→        fontSize: "13px",
    70→        color: isSuccess ? "#166534" : "#991b1b",
    71→        minWidth: "280px",
    72→        maxWidth: "420px",
    73→      }}
    74→    >
    75→      {isSuccess ? (
    76→        <CheckCircle2 className="h-4 w-4 shrink-0" style={{ color: "#16a34a" }} />
    77→      ) : (
    78→        <XCircle className="h-4 w-4 shrink-0" style={{ color: "#dc2626" }} />
    79→      )}
    80→      <span className="flex-1">{toast.message}</span>
    81→      <button
    82→        onClick={() => onDismiss(toast.id)}
    83→        className="shrink-0 rounded p-0.5 transition-colors hover:bg-black/5"
    84→      >
    85→        <X className="h-3.5 w-3.5" />
    86→      </button>
    87→    </div>
    88→  );
    89→}
    90→

