    15→interface ConfirmDialogProps {
    16→  open: boolean;
    17→  onOpenChange: (open: boolean) => void;
    18→  title: string;
    19→  description: string;
    20→  onConfirm: () => Promise<void>;
    21→  confirmLabel?: string;
    22→}
    23→
    24→export function ConfirmDialog({
    25→  open,
    26→  onOpenChange,
    27→  title,
    28→  description,
    29→  onConfirm,
    30→  confirmLabel,
    31→}: ConfirmDialogProps) {
    32→  const { t } = useTranslation();
    33→  const [loading, setLoading] = useState(false);
    34→
    35→  const handleConfirm = async () => {
    36→    setLoading(true);
    37→    try {
    38→      await onConfirm();
    39→      onOpenChange(false);
    40→    } finally {
    41→      setLoading(false);
    42→    }
    43→  };
    44→
    45→  return (
    46→    <Dialog open={open} onOpenChange={onOpenChange}>
    47→      <DialogContent className="sm:max-w-md">
