    51→        </DialogHeader>
    52→        <DialogFooter>
    53→          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
    54→            {t("confirmDialog.cancel")}
    55→          </Button>
    56→          <Button variant="destructive" onClick={handleConfirm} disabled={loading}>
    57→            {loading ? t("confirmDialog.deleting") : (confirmLabel ?? t("confirmDialog.confirm"))}
    58→          </Button>
    59→        </DialogFooter>
    60→      </DialogContent>
    61→    </Dialog>
    62→  );
    63→}
