     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR from "swr";
     5→import type { Source } from "@/lib/api/types";
     6→
     7→const PROVIDER_PRIORITY: Record<string, number> = {
     8→  github: 0,
     9→  gitlab: 1,
    10→  dockerhub: 2,
    11→  "ecr-public": 3,
    12→};
    13→
    14→interface AvatarCandidate {
    15→  url: string;
    16→  async?: false;
    17→}
    18→
    19→interface AsyncAvatarCandidate {
    20→  provider: "gitlab";
    21→  owner: string;
    22→  async: true;
    23→}
    24→
    25→type AvatarResult = AvatarCandidate | AsyncAvatarCandidate | null;
    26→
    27→function getAvatarCandidate(sources: Source[]): AvatarResult {
    28→  const sorted = [...sources]
    29→    .filter((s) => s.provider in PROVIDER_PRIORITY)
    30→    .sort((a, b) => (PROVIDER_PRIORITY[a.provider] ?? 99) - (PROVIDER_PRIORITY[b.provider] ?? 99));
    31→
    32→  for (const source of sorted) {
    33→    const owner = source.repository.split("/")[0];
    34→    if (!owner) continue;
    35→
    36→    if (source.provider === "github") {
    37→      return { url: `https://github.com/${owner}.png?size=64` };
    38→    }
    39→    if (source.provider === "gitlab") {
    40→      return { provider: "gitlab", owner, async: true };
    41→    }
    42→  }
    43→  return null;
    44→}
    45→
    46→async function fetchGitLabAvatar(owner: string): Promise<string | null> {
    47→  try {
    48→    const res = await fetch(`https://gitlab.com/api/v4/groups/${encodeURIComponent(owner)}`);
    49→    if (res.ok) {
    50→      const data = await res.json();
    51→      if (data.avatar_url) return data.avatar_url;
    52→    }
    53→    // Try as user if group lookup fails
    54→    const userRes = await fetch(`https://gitlab.com/api/v4/users?username=${encodeURIComponent(owner)}`);
    55→    if (userRes.ok) {
    56→      const users = await userRes.json();
    57→      if (users[0]?.avatar_url) return users[0].avatar_url;
    58→    }
    59→  } catch {
    60→    // Network error — fall back to placeholder
    61→  }
    62→  return null;
    63→}
    64→
    65→function hashCode(str: string): number {
    66→  let hash = 0;
    67→  for (let i = 0; i < str.length; i++) {
    68→    hash = ((hash << 5) - hash + str.charCodeAt(i)) | 0;
    69→  }
    70→  return Math.abs(hash);
    71→}
    72→
    73→const PLACEHOLDER_COLORS = [
    74→  "#e8601a", "#2496ed", "#16a34a", "#7c3aed",
    75→  "#dc2626", "#0891b2", "#c026d3", "#ca8a04",
    76→  "#4f46e5", "#059669", "#d97706", "#9333ea",
    77→];
    78→
    79→interface ProjectLogoProps {
    80→  name: string;
    81→  sources?: Source[];
    82→  size?: number;
    83→}
    84→
    85→export function ProjectLogo({ name, sources = [], size = 40 }: ProjectLogoProps) {
    86→  const [imgError, setImgError] = useState(false);
    87→  const candidate = getAvatarCandidate(sources);
    88→
    89→  const gitlabOwner = candidate?.async ? candidate.owner : null;
    90→  const { data: gitlabAvatarUrl } = useSWR(
    91→    gitlabOwner ? `gitlab-avatar-${gitlabOwner}` : null,
    92→    () => fetchGitLabAvatar(gitlabOwner!),
    93→  );
    94→
    95→  const avatarUrl = candidate?.async ? gitlabAvatarUrl ?? null : candidate?.url ?? null;
    96→  const showImg = avatarUrl && !imgError;
    97→
    98→  const initial = (name[0] ?? "?").toUpperCase();
    99→  const color = PLACEHOLDER_COLORS[hashCode(name) % PLACEHOLDER_COLORS.length];
   100→  const fontSize = Math.max(10, Math.round(size * 0.45));
   101→
   102→  if (showImg) {
   103→    return (
   104→      <img
   105→        src={avatarUrl}
   106→        alt={`${name} logo`}
   107→        width={size}
   108→        height={size}
   109→        onError={() => setImgError(true)}
   110→        className="shrink-0 rounded-md object-cover"
   111→        style={{ width: size, height: size }}
   112→      />
   113→    );
   114→  }
   115→
   116→  return (
   117→    <div
   118→      className="shrink-0 rounded-md flex items-center justify-center select-none"
   119→      style={{
   120→        width: size,
   121→        height: size,
   122→        backgroundColor: color,
   123→        fontSize,
   124→        fontFamily: "var(--font-raleway), sans-serif",
   125→        fontWeight: 700,
   126→        color: "#ffffff",
   127→      }}
   128→      aria-label={`${name} logo`}
   129→    >
   130→      {initial}
   131→    </div>
   132→  );
   133→}
