    58→/* Chip sub-component */
    59→
    60→function Chip({
    61→  label,
    62→  displayValue,
    63→  onRemove,
    64→  onClick,
    65→}: {
    66→  label: string;
    67→  displayValue: string;
    68→  onRemove: () => void;
