    74→      onClick={onClick}
    75→      className="inline-flex items-center gap-1.5 rounded-full border border-border bg-surface-secondary px-2.5 py-1 text-xs transition-colors hover:bg-surface-tertiary"
    76→      style={{ fontFamily: "var(--font-dm-sans)" }}
