    79→      <span className="text-text-primary">{displayValue}</span>
    80→      <span
    81→        role="button"
    82→        tabIndex={0}
    83→        className="ml-0.5 text-text-muted hover:text-text-primary"
    84→        onClick={(e) => { e.stopPropagation(); onRemove(); }}
    85→        onKeyDown={(e) => { if (e.key === "Enter") { e.stopPropagation(); onRemove(); } }}
    86→      >
    87→        <X size={12} />
    88→      </span>
    89→    </button>
    90→  );
