    93→/* FilterBar */
    94→
    95→export function FilterBar({ filters, value, onChange }: FilterBarProps) {
    96→  const [popoverOpen, setPopoverOpen] = useState(false);
    97→  const [selectedType, setSelectedType] = useState<string | null>(null);
    98→  const [search, setSearch] = useState("");
    99→  const popoverRef = useRef<HTMLDivElement>(null);
   100→
   101→  useEffect(() => {
   102→    function handleClick(e: MouseEvent) {
   103→      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
   104→        setPopoverOpen(false);
   105→        setSelectedType(null);
   106→        setSearch("");
   107→      }
   108→    }
   109→    if (popoverOpen) {
   110→      document.addEventListener("mousedown", handleClick);
   111→      return () => document.removeEventListener("mousedown", handleClick);
   112→    }
   113→  }, [popoverOpen]);
   114→
   115→  const activeFilters = filters.filter(
   116→    (f) => value[f.key] !== undefined && value[f.key] !== ""
   117→  );
   118→  const availableFilters = filters.filter(
   119→    (f) => value[f.key] === undefined || value[f.key] === ""
   120→  );
   121→
   122→  const getDisplayValue = (config: FilterConfig, val: string): string => {
   123→    if (config.type === "boolean") return val === "true" ? "Yes" : "No";
   124→    if (config.type === "date-range") {
   125→      const preset = DATE_PRESETS.find((p) => p.value === val);
   126→      if (preset) return preset.label;
   127→      return val;
   128→    }
   129→    if (config.options) {
   130→      const opt = config.options.find((o) => o.value === val);
   131→      if (opt) return opt.label;
   132→    }
   133→    return val;
   134→  };
   135→
   136→  const removeFilter = (key: string) => {
   137→    const next = { ...value };
   138→    delete next[key];
   139→    if (key === "date") {
   140→      delete next["date_from"];
   141→      delete next["date_to"];
   142→    }
   143→    onChange(next);
   144→  };
   145→
   146→  const setFilter = (key: string, val: string) => {
   147→    onChange({ ...value, [key]: val });
   148→    setPopoverOpen(false);
   149→    setSelectedType(null);
   150→    setSearch("");
   151→  };
   152→
   153→  const openFilterEdit = (key: string) => {
   154→    setSelectedType(key);
   155→    setPopoverOpen(true);
   156→    setSearch("");
   157→  };
   158→
   159→  const clearAll = () => onChange({});
   160→
   161→  const hasActiveFilters = activeFilters.length > 0;
   162→  const selectedConfig = selectedType ? filters.find((f) => f.key === selectedType) : null;
   163→
   164→  return (
   165→    <div className="flex flex-wrap items-center gap-2 rounded-lg border border-border bg-surface px-3 py-2">
   166→      {activeFilters.map((config) => (
   167→        <Chip
   168→          key={config.key}
   169→          label={config.label}
   170→          displayValue={getDisplayValue(config, value[config.key])}
   171→          onRemove={() => removeFilter(config.key)}
   172→          onClick={() => openFilterEdit(config.key)}
   173→        />
   174→      ))}
   175→
   176→      {availableFilters.length > 0 && (
   177→        <div className="relative" ref={popoverRef}>
   178→          <button
   179→            type="button"
   180→            onClick={() => { setPopoverOpen(!popoverOpen); setSelectedType(null); setSearch(""); }}
   181→            className="inline-flex items-center gap-1 rounded-full border border-dashed border-border px-2.5 py-1 text-xs text-text-muted transition-colors hover:border-border-strong hover:text-text-secondary"
   182→            style={{ fontFamily: "var(--font-dm-sans)" }}
   183→          >
   184→            <Plus size={12} />
   185→            Add filter
   186→          </button>
   187→
   188→          {popoverOpen && (
   189→            <div className="absolute left-0 top-full z-50 mt-1 flex overflow-hidden rounded-lg border border-border bg-surface shadow-lg">
   190→              {!selectedType && (
   191→                <div className="w-44 py-1">
   192→                  <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider text-text-muted">
   193→                    Filter by
   194→                  </div>
   195→                  {availableFilters.map((config) => (
   196→                    <button
   197→                      key={config.key}
   198→                      type="button"
   199→                      onClick={() => {
   200→                        if (config.type === "boolean") {
   201→                          setFilter(config.key, "true");
   202→                        } else {
   203→                          setSelectedType(config.key);
   204→                        }
   205→                      }}
   206→                      className="flex w-full items-center px-3 py-1.5 text-left text-xs text-text-secondary transition-colors hover:bg-surface-secondary"
   207→                      style={{ fontFamily: "var(--font-dm-sans)" }}
   208→                    >
   209→                      {config.label}
   210→                    </button>
   211→                  ))}
   212→                </div>
   213→              )}
   214→
   215→              {selectedConfig && selectedConfig.type === "select" && (
   216→                <div className="w-52 py-1">
   217→                  <div className="px-2 pb-1">
   218→                    <div className="flex items-center gap-1.5 rounded border border-border bg-background px-2 py-1">
   219→                      <Search size={12} className="text-text-muted" />
   220→                      <input
   221→                        type="text"
   222→                        value={search}
   223→                        onChange={(e) => setSearch(e.target.value)}
   224→                        placeholder={`Search ${selectedConfig.label.toLowerCase()}...`}
   225→                        className="w-full bg-transparent text-xs text-text-primary outline-none placeholder:text-text-muted"
   226→                        autoFocus
   227→                      />
   228→                    </div>
   229→                  </div>
   230→                  <div className="max-h-48 overflow-y-auto">
   231→                    {(selectedConfig.options ?? [])
   232→                      .filter((opt) => opt.label.toLowerCase().includes(search.toLowerCase()))
   233→                      .map((opt) => {
   234→                        const isActive = value[selectedConfig.key] === opt.value;
   235→                        return (
   236→                          <button
   237→                            key={opt.value}
   238→                            type="button"
   239→                            onClick={() => setFilter(selectedConfig.key, opt.value)}
   240→                            className="flex w-full items-center gap-2 px-3 py-1.5 text-left text-xs transition-colors hover:bg-surface-secondary"
   241→                            style={{ fontFamily: "var(--font-dm-sans)" }}
   242→                          >
   243→                            <span className={isActive ? "text-text-primary font-medium" : "text-text-secondary"}>
   244→                              {opt.label}
   245→                            </span>
   246→                            {isActive && <Check size={12} className="ml-auto text-accent" />}
   247→                          </button>
   248→                        );
   249→                      })}
   250→                  </div>
   251→                </div>
   252→              )}
   253→
   254→              {selectedConfig && selectedConfig.type === "date-range" && (
   255→                <div className="w-52 py-1">
   256→                  <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider text-text-muted">
   257→                    Date range
   258→                  </div>
   259→                  {DATE_PRESETS.map((preset) => (
   260→                    <button
   261→                      key={preset.value}
   262→                      type="button"
   263→                      onClick={() => setFilter("date", preset.value)}
   264→                      className="flex w-full items-center px-3 py-1.5 text-left text-xs text-text-secondary transition-colors hover:bg-surface-secondary"
   265→                      style={{ fontFamily: "var(--font-dm-sans)" }}
   266→                    >
   267→                      {preset.label}
   268→                    </button>
   269→                  ))}
   270→                </div>
   271→              )}
   272→            </div>
   273→          )}
   274→        </div>
   275→      )}
   276→
   277→      {hasActiveFilters && (
   278→        <button
   279→          type="button"
   280→          onClick={clearAll}
   281→          className="ml-auto text-[11px] text-text-muted transition-colors hover:text-text-secondary"
   282→          style={{ fontFamily: "var(--font-dm-sans)" }}
   283→        >
   284→          Clear all
   285→        </button>
   286→      )}
   287→    </div>
   288→  );
   289→}
