     1→/**
     2→ * Urgency Pill — shared badge component for semantic release urgency.
     3→ *
     4→ * ## Urgency Levels
     5→ *
     6→ * | Level    | Icon            | Color   | Meaning                                    |
     7→ * |----------|-----------------|---------|--------------------------------------------|
     8→ * | critical | AlertOctagon    | Red     | Breaking changes, security patches          |
     9→ * | high     | AlertTriangle   | Orange  | Significant API changes, deprecations       |
    10→ * | medium   | Circle          | Amber   | Notable changes worth reviewing             |
    11→ * | low      | CheckCircle     | Green   | Routine updates, dependency bumps           |
    12→ *
    13→ * ## Variants
    14→ *
    15→ * - **icon-only** (default): 18×18 circle with just the icon. Best for compact
    16→ *   spaces like the projects page where multiple versions are listed inline.
    17→ *   Urgency label is shown on hover via `title`.
    18→ *
    19→ * - **labeled**: Icon + text label in a rounded pill. Best for table rows
    20→ *   (releases page) where there's dedicated column space.
    21→ *
    22→ * - **text**: Text-only pill without icon. Best for table cells and compact
    23→ *   lists where space is tight but the label should be visible.
    24→ */
    25→import { AlertOctagon, AlertTriangle, Circle, CheckCircle } from "lucide-react";
    26→import type { LucideIcon } from "lucide-react";
    27→
    28→interface UrgencyStyle {
    29→  icon: LucideIcon;
    30→  bg: string;
    31→  border: string;
    32→  text: string;
    33→}
    34→
    35→export const URGENCY_STYLES: Record<string, UrgencyStyle> = {
    36→  critical: { icon: AlertOctagon, bg: "rgba(220,38,38,0.10)", border: "rgba(220,38,38,0.20)", text: "#dc2626" },
    37→  high:     { icon: AlertTriangle, bg: "rgba(249,115,22,0.10)", border: "rgba(249,115,22,0.20)", text: "#ea580c" },
    38→  medium:   { icon: Circle,        bg: "rgba(245,158,11,0.10)", border: "rgba(245,158,11,0.20)", text: "#d97706" },
    39→  low:      { icon: CheckCircle,   bg: "rgba(34,197,94,0.08)",  border: "rgba(34,197,94,0.18)",  text: "#16a34a" },
    40→};
    41→
    42→interface UrgencyPillProps {
    43→  urgency: string;
    44→  /** "icon-only" = compact circle, "labeled" = icon + text pill, "text" = text-only pill */
    45→  variant?: "icon-only" | "labeled" | "text";
    46→  className?: string;
    47→}
    48→
    49→export function UrgencyPill({ urgency, variant = "icon-only", className }: UrgencyPillProps) {
    50→  const style = URGENCY_STYLES[urgency.toLowerCase()];
    51→  if (!style) return null;
    52→
    53→  const Icon = style.icon;
    54→
    55→  if (variant === "icon-only") {
    56→    return (
    57→      <span
    58→        className={`inline-flex items-center justify-center rounded-full ${className ?? ""}`}
    59→        style={{ backgroundColor: style.bg, border: `1px solid ${style.border}`, color: style.text, width: 18, height: 18 }}
    60→        title={urgency}
    61→      >
    62→        <Icon size={10} />
    63→      </span>
    64→    );
    65→  }
    66→
    67→  if (variant === "text") {
    68→    return (
    69→      <span
    70→        className={`inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none ${className ?? ""}`}
    71→        style={{ backgroundColor: style.bg, border: `1px solid ${style.border}`, color: style.text, fontFamily: "var(--font-dm-sans)" }}
    72→        title={urgency}
    73→      >
    74→        {urgency}
    75→      </span>
    76→    );
    77→  }
    78→
    79→  return (
    80→    <span
    81→      className={`inline-flex items-center gap-0.5 rounded-full px-2 py-0.5 text-[10px] font-semibold ${className ?? ""}`}
    82→      style={{ backgroundColor: style.bg, border: `1px solid ${style.border}`, color: style.text, fontFamily: "var(--font-dm-sans)" }}
    83→      title={urgency}
    84→    >
    85→      <Icon size={10} /> {urgency}
    86→    </span>
    87→  );
    88→}
