    27→/* Date presets */
    28→
    29→const DATE_PRESETS: FilterOption[] = [
    30→  { value: "7d", label: "Last 7 days" },
    31→  { value: "30d", label: "Last 30 days" },
    32→  { value: "90d", label: "Last 90 days" },
    33→  { value: "1y", label: "Last year" },
