    35→
    36→export function expandDatePreset(preset: string): { date_from: string; date_to?: string } {
    37→  const now = new Date();
    38→  let from: Date;
    39→  switch (preset) {
    40→    case "7d":
    41→      from = new Date(now.getTime() - 7 * 86400000);
    42→      break;
    43→    case "30d":
    44→      from = new Date(now.getTime() - 30 * 86400000);
    45→      break;
    46→    case "90d":
    47→      from = new Date(now.getTime() - 90 * 86400000);
    48→      break;
    49→    case "1y":
    50→      from = new Date(now.getTime() - 365 * 86400000);
    51→      break;
    52→    default:
    53→      return { date_from: preset };
    54→  }
    55→  return { date_from: from.toISOString().slice(0, 10) };
    56→}
