    92→    () => fetchGitLabAvatar(gitlabOwner!),
    93→  );
    94→
    95→  const avatarUrl = candidate?.async ? gitlabAvatarUrl ?? null : candidate?.url ?? null;
    96→  const showImg = avatarUrl && !imgError;
    97→
    98→  const initial = (name[0] ?? "?").toUpperCase();
    99→  const color = PLACEHOLDER_COLORS[hashCode(name) % PLACEHOLDER_COLORS.length];
   100→  const fontSize = Math.max(10, Math.round(size * 0.45));
   101→
   102→  if (showImg) {
