     1→"use client";
     2→
     3→import { useState, useCallback, useEffect } from "react";
     4→
     5→/**
     6→ * useFilterParams syncs a Record<string, string> of filter values with URL query params.
     7→ * Only reads/writes params whose keys are in `allowedKeys` to prevent cross-page leakage.
     8→ */
     9→export function useFilterParams(
    10→  allowedKeys: string[],
    11→  defaults?: Record<string, string>
    12→): {
    13→  filters: Record<string, string>;
    14→  setFilters: (next: Record<string, string>) => void;
    15→  page: number;
    16→  setPage: (p: number) => void;
    17→} {
    18→  const [filters, setFiltersState] = useState<Record<string, string>>(() => {
    19→    if (typeof window === "undefined") return defaults ?? {};
    20→    const params = new URLSearchParams(window.location.search);
    21→    const parsed: Record<string, string> = { ...(defaults ?? {}) };
    22→    const allowed = new Set(allowedKeys);
    23→    params.forEach((value, key) => {
    24→      if (key !== "page" && allowed.has(key)) {
    25→        parsed[key] = value;
    26→      }
    27→    });
    28→    return parsed;
    29→  });
    30→
    31→  const [page, setPageState] = useState<number>(() => {
    32→    if (typeof window === "undefined") return 1;
    33→    const params = new URLSearchParams(window.location.search);
    34→    const p = params.get("page");
    35→    if (!p) return 1;
    36→    // If URL contains params not in this page's allowed set, it's a
    37→    // cross-page navigation (e.g. releases?excluded=true&page=3 -> /todo)
    38→    // — reset page to 1 to avoid carrying stale pagination.
    39→    const allowed = new Set([...allowedKeys, "page"]);
    40→    const hasStaleParams = Array.from(params.keys()).some((k) => !allowed.has(k));
    41→    if (hasStaleParams) return 1;
    42→    return Math.max(1, parseInt(p, 10) || 1);
    43→  });
    44→
    45→  useEffect(() => {
    46→    const url = new URL(window.location.href);
    47→    Array.from(url.searchParams.keys()).forEach((k) =>
    48→      url.searchParams.delete(k)
    49→    );
    50→    for (const [key, value] of Object.entries(filters)) {
    51→      if (value !== "" && value !== undefined) {
    52→        url.searchParams.set(key, value);
    53→      }
    54→    }
    55→    if (page > 1) {
    56→      url.searchParams.set("page", String(page));
    57→    }
    58→    window.history.replaceState({}, "", url.toString());
    59→  }, [filters, page]);
    60→
    61→  const setFilters = useCallback((next: Record<string, string>) => {
    62→    setFiltersState(next);
    63→    setPageState(1);
    64→  }, []);
    65→
    66→  const setPage = useCallback((p: number) => {
    67→    setPageState(p);
    68→  }, []);
    69→
    70→  return { filters, setFilters, page, setPage };
    71→}
