    38→export function formatInterval(seconds: number): string {
    39→  if (seconds === 3600) return "Hourly";
    40→  if (seconds === 86400) return "Daily";
    41→  if (seconds === 604800) return "Weekly";
    42→  if (seconds === 2592000) return "Monthly";
    43→  if (seconds < 60) return `${seconds}s`;
    44→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    45→  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)}h`;
    46→  return `${(seconds / 86400).toFixed(1)}d`;
    47→}
