     1→"use client";
     2→
     3→import {
     4→  createContext,
     5→  useContext,
     6→  useState,
     7→  useCallback,
     8→  type ReactNode,
     9→} from "react";
    10→import en from "./messages/en.json";
    11→import zh from "./messages/zh.json";
    12→
    13→const messages: Record<string, Record<string, string>> = { en, zh };
    14→
    15→type Locale = "en" | "zh";
    16→
    17→interface I18nContextValue {
    18→  locale: Locale;
    19→  setLocale: (locale: Locale) => void;
    20→  t: (key: string) => string;
    21→}
    22→
    23→const I18nContext = createContext<I18nContextValue | null>(null);
    24→
    25→const STORAGE_KEY = "changelogue-locale";
    26→
    27→function getInitialLocale(): Locale {
    28→  if (typeof window === "undefined") return "en";
    29→  const stored = localStorage.getItem(STORAGE_KEY);
    30→  if (stored === "en" || stored === "zh") {
    31→    document.documentElement.lang = stored;
    32→    return stored;
    33→  }
    34→  return "en";
    35→}
    36→
    37→export function LanguageProvider({ children }: { children: ReactNode }) {
    38→  const [locale, setLocaleState] = useState<Locale>(getInitialLocale);
    39→
    40→  const setLocale = useCallback((next: Locale) => {
    41→    setLocaleState(next);
    42→    localStorage.setItem(STORAGE_KEY, next);
    43→    document.documentElement.lang = next;
    44→  }, []);
    45→
    46→  const t = useCallback(
    47→    (key: string): string => {
    48→      return messages[locale]?.[key] ?? messages.en?.[key] ?? key;
    49→    },
    50→    [locale]
    51→  );
    52→
    53→  return (
    54→    <I18nContext.Provider value={{ locale, setLocale, t }}>
    55→      {children}
    56→    </I18nContext.Provider>
    57→  );
    58→}
    59→
    60→export function useTranslation() {
    61→  const ctx = useContext(I18nContext);
    62→  if (!ctx) throw new Error("useTranslation must be used within LanguageProvider");
    63→  return ctx;
    64→}
